// A fresh Studio window that never once reports a browser connection within this
// grace of its launch never actually surfaced (a headless/remote spawn, or a
// browser that refused after handoff - the case where Studio "opened" but no
// window appeared). Two independent safety nets both key off this same grace, so
// they stay in lockstep:
//   - the daemon reaper (daemon/server.ts) ends + reaps the phantom session for
//     the fire-and-forget / durable-log consumers;
//   - the in-process connect watchdog (commands/openStudioTo.ts) synthesizes the
//     terminal for onEvent consumers, on BOTH the daemon and direct channels.
// Generous by default so a user clicking the surfaced Studio URL still connects
// before either fires; overridable via env so tests don't wait.
const CONNECT_GRACE_MS = 45_000;
export function connectGraceMs() {
    const raw = process.env.BITFAB_STUDIO_CONNECT_GRACE_MS;
    const parsed = raw ? Number(raw) : Number.NaN;
    return Number.isFinite(parsed) ? parsed : CONNECT_GRACE_MS;
}
// The long "a human must act by hand" never-connected grace, used wherever the
// short grace would race a person instead of a machine: a pre-auth (keyless
// login) session, where the user may be typing a password on a sign-in page
// that is not guaranteed to report as a browser connection; and a failed
// browser launch, where open-failed surfaced a URL and told the user to click
// it manually. Matches the login flow's own polling timeout (LOGIN_TIMEOUT_MS),
// the real backstop for an abandoned manual step.
const PRE_AUTH_CONNECT_GRACE_MS = 10 * 60 * 1000;
export function preAuthConnectGraceMs() {
    const raw = process.env.BITFAB_STUDIO_PREAUTH_CONNECT_GRACE_MS;
    const parsed = raw ? Number(raw) : Number.NaN;
    return Number.isFinite(parsed) ? parsed : PRE_AUTH_CONNECT_GRACE_MS;
}
